def validate_transformation(xform):
    problems = []

    # T1: Check all listed fields are present
    required_fields = [
        'transformation_id',
        'transformation_type',
        'input_refs',
        'output_refs',
        'basis_refs',
        'operation',
        'retained_uncertainty',
        'excluded_scope',
        'revision_triggers'
    ]

    for field in required_fields:
        if field not in xform:
            return {"ok": False, "problems": [f"Missing required field: {field}"]}

    # T2: transformation_type must be one of the allowed values
    allowed_types = [
        'RAW_REQUEST_TO_RESOLVED_INTENT',
        'RESOLVED_INTENT_TO_RESEARCH_DESIGN',
        'RESEARCH_AXIS_TO_RQ',
        'OBSERVATION_TO_EVIDENCE',
        'EVIDENCE_TO_CLAIM'
    ]
    if xform['transformation_type'] not in allowed_types:
        return {"ok": False, "problems": ["Invalid transformation_type"]}

    # T3: input_refs, output_refs, basis_refs must each be a non-empty list
    list_fields_required = ['input_refs', 'output_refs', 'basis_refs']
    for field in list_fields_required:
        val = xform[field]
        if not isinstance(val, list):
            return {"ok": False, "problems": [f"{field} must be a list"]}
        if len(val) == 0:
            return {"ok": False, "problems": [f"{field} must be non-empty"]}

    # T4: retained_uncertainty, excluded_scope, revision_triggers must each be a list
    list_fields_optional = ['retained_uncertainty', 'excluded_scope', 'revision_triggers']
    for field in list_fields_optional:
        val = xform[field]
        if not isinstance(val, list):
            return {"ok": False, "problems": [f"{field} must be a list"]}

    # T5: operation must be a non-empty string
    if not isinstance(xform['operation'], str) or len(xform['operation']) == 0:
        return {"ok": False, "problems": ["operation must be a non-empty string"]}

    # T6: C-TOTALITY: Check all fields are of correct type (non-dict or wrong-type -> ok False)
    # Check transformation_id is a string
    if not isinstance(xform['transformation_id'], str):
        return {"ok": False, "problems": ["transformation_id must be a string"]}

    # Check operation is a string (already checked above, but included for completeness)
    # Already handled in T5

    # Check all list fields are actually lists (already handled in T3 and T4)

    # If we reach here, all validations passed
    return {"ok": True, "problems": []}
